import{c as a,S as e,j as i,m as l}from"./chunks/framework.-AwLDeHv.js";const c=JSON.parse('{"title":"Roadmap","description":"","frontmatter":{},"headers":[],"relativePath":"roadmap.md","filePath":"roadmap.md","lastUpdated":null}'),r={name:"roadmap.md"};function o(s,t,n,d,h,g){return e(),i("div",null,[...t[0]||(t[0]=[l('<h1 id="Roadmap" tabindex="-1">Roadmap <a class="header-anchor" href="#Roadmap" aria-label="Permalink to &quot;Roadmap {#Roadmap}&quot;">​</a></h1><p>GLLVM.jl is being built as a fast Julia <strong>digital twin of <a href="https://itchyshin.github.io/gllvmTMB/" target="_blank" rel="noreferrer"><code>gllvmTMB</code></a></strong>: the same model syntax, usable directly in Julia and (in the future) through R, across all response families. The live, detailed roadmap — with linked issues — is tracked on GitHub:</p><p>➡️ <strong><a href="https://github.com/itchyshin/GLLVM.jl/issues/11" target="_blank" rel="noreferrer">GLLVM.jl roadmap (issue #11)</a></strong></p><h2 id="Phase-release-map" tabindex="-1">Phase → release map <a class="header-anchor" href="#Phase-release-map" aria-label="Permalink to &quot;Phase → release map {#Phase-release-map}&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:right;">Release</th><th style="text-align:right;">Theme</th><th style="text-align:right;">Highlights</th></tr></thead><tbody><tr><td style="text-align:right;"><strong>v0.2.0</strong></td><td style="text-align:right;">Gaussian complete</td><td style="text-align:right;">O(p) phylogenetic fitter, <code>predict</code>/<code>residuals</code>/<code>summary</code>, this docs site</td></tr><tr><td style="text-align:right;"><strong>v0.3.0</strong></td><td style="text-align:right;">Binary + first tutorials</td><td style="text-align:right;"><code>Family</code> abstraction + Binomial (first non-Gaussian), the <code>gllvm()</code> <code>@formula</code> front-end, gllvmTMB-mirroring tutorials</td></tr><tr><td style="text-align:right;"><strong>v1.0</strong></td><td style="text-align:right;">Full digital twin</td><td style="text-align:right;">all families, full extractor / ordination / diagnostic parity, ~16 tutorials, the R bridge (<code>engine = &quot;julia&quot;</code>)</td></tr></tbody></table><h2 id="What-works-today" tabindex="-1">What works today <a class="header-anchor" href="#What-works-today" aria-label="Permalink to &quot;What works today {#What-works-today}&quot;">​</a></h2><ul><li><p>Gaussian + phylogenetic GLLVM fitting (closed-form marginal).</p></li><li><p>An <strong>O(p)</strong> phylogenetic gradient — exact, linear-in-species scaling.</p></li><li><p>Wald / profile-likelihood / parametric-bootstrap confidence intervals, including derived quantities (Σ_y, communality, phylogenetic signal).</p></li></ul><h2 id="What&#39;s-planned" tabindex="-1">What&#39;s planned <a class="header-anchor" href="#What&#39;s-planned" aria-label="Permalink to &quot;What&#39;s planned {#What&#39;s-planned}&quot;">​</a></h2><ul><li><p><strong>Families</strong> beyond Gaussian — binary first, then Poisson, negative binomial, ordinal, beta, hurdle / zero-inflated — via a Laplace marginal.</p></li><li><p><strong>Same-as-R model syntax</strong>: <code>gllvm(@formula(traits(...) ~ … + phylo(...)), data; family = …)</code>.</p></li><li><p><strong>The R bridge</strong> — run a <code>gllvmTMB</code> model through the Julia engine (<code>engine = &quot;julia&quot;</code>).</p></li></ul><p>This roadmap evolves; issue #11 is always current.</p>',10)])])}const m=a(r,[["render",o]]);export{c as __pageData,m as default};
